const EXCLUDE_PREFIXES = [/^Detalhe_/i, /^News_/i];
const items = $input.all();
const results = [];
const seen = new Set();

for (const item of items) {
  const binaryKeys = item.binary ? Object.keys(item.binary) : [];
  let actualData = null;
  let mimeType = '';
  let fileName = '';

  for (const key of binaryKeys) {
    const wrapper = item.binary[key];
    if (wrapper?.data) {
      actualData = wrapper;
      mimeType = wrapper.mimeType || '';
      fileName = wrapper.fileName || item.json.fileName || '';
      break;
    }
  }

  if (!actualData) continue;

  fileName = fileName.trim();
  const isPdf = mimeType.toLowerCase().includes('pdf') || fileName.toLowerCase().endsWith('.pdf');
  if (!isPdf) continue;
  if (EXCLUDE_PREFIXES.some(re => re.test(fileName))) continue;

  const msgId = item.json.id || item.json.messageId || fileName;
  if (seen.has(msgId)) continue;
  seen.add(msgId);

  // Detect personal banking docs (NL / EXTRATO COMBINADO) — skip LLM rename
  const isPersonal = /^NL\s+\d/i.test(fileName) || /^EXTRATO\s/i.test(fileName);

  results.push({ json: { fileName, personalDoc: isPersonal }, binary: { data: actualData } });
}
return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const markdown = item.json.markdown || item.json.text || '';
  const fileName = item.json.fileName || '';

  if (!markdown || markdown.length < 20) {
    results.push({ json: { fileName, text: '', extractError: 'No text extracted' }, binary: item.binary });
    continue;
  }

  let text = markdown.replace(/!\[.*?\]\(data:image\/[^)]+\)/gi, '');
  text = text.replace(/<img[^>]*>/gi, '');
  text = text.replace(/\n{3,}/g, '\n\n').replace(/[ \t]{2,}/g, ' ').trim();
  if (text.length > 5000) text = text.substring(0, 5000);

  results.push({ json: { fileName, text }, binary: item.binary });
}
return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const text = item.json.text || item.json.markdown || '';
  const fileName = item.json.fileName || '';

  const isNL = /^NL[_-]?/i.test(fileName);
