    prompt = 'Extrai dados da Nota de Lançamento. Retorna APENAS JSON sem explicacao.\n\n' +
      'Campos:\n' +
      '- emitente: nome do banco ou entidade em MAIUSCULAS, sem particulas. Max 20 caracteres.\n' +
      '- nif: NIF da entidade, so digitos, sem espacos (pode ser null se nao aparecer)\n' +
      '- data_emissao: data no formato YYYY-MM\n' +
      '- tipo: "NL" sempre\n' +
      '- numero: numero da nota de lancamento\n' +
      '- valor: valor total (string com 2 casas decimais)\n' +
      '- descricao: pequena descricao da transacao (max 100 chars)\n\n' +
      'Se nao for Nota de Lancamento: {"erro":"nao_e_nl"}\n\n' +
      'Texto:\n' + text.substring(0, 4000);
  } else if (isEX) {
    prompt = 'Extrai dados do Extrato Bancario. Retorna APENAS JSON sem explicacao.\n\n' +
      'Campos:\n' +
      '- emitente: nome do banco em MAIUSCULAS, sem particulas. Max 20 caracteres.\n' +
      '- nif: NIF do banco, so digitos (pode ser null)\n' +
      '- data_emissao: data do extrato no formato YYYY-MM\n' +
      '- tipo: "EX" sempre\n' +
      '- numero: numero do extrato ou referencia\n' +
      '- saldo_inicial: saldo inicial (string com 2 casas decimais)\n' +
      '- saldo_final: saldo final (string com 2 casas decimais)\n' +
      '- total_creditos: total de creditos (string com 2 casas decimais)\n' +
      '- total_debitos: total de debitos (string com 2 casas decimais)\n\n' +
      'Se nao for Extrato Bancario: {"erro":"nao_e_extrato"}\n\n' +
      'Texto:\n' + text.substring(0, 4000);
  } else {
    prompt = 'Extrai dados do documento fiscal. Retorna APENAS JSON sem explicacao.\n\n' +
      'Campos:\n' +
      '- emitente: nome da empresa que emitiu, em MAIUSCULAS, sem particulas como "S.A.", "Lda.", "Unipessoal", "Comunicacoes", "Servicos", "Sociedade". Apenas a marca principal. Exemplos: "MEO", "NOS", "VODAFONE", "GRENKE", "MILLENNIUMBCP", "VIAVERDE", "PRIO", "ALCOCHETEUP", "EGITANA". Max 20 caracteres.\n' +
      '- nif: NIF do emitente, so digitos, sem espacos\n' +
      '- data_emissao: data de emissao no formato YYYY-MM\n' +
      '- tipo: "FT" fatura, "ND" nota debito, "NC" nota credito, "FS" fatura simplificada, "EX" extrato bancario, "NL" nota liquidacao, "REC" recibo, "OUTRO" outros\n' +
      '- numero: numero do documento\n\n' +
      'Se nao for documento fiscal: {"erro":"nao_e_fiscal"}\n' +
      'Se nao conseguir um campo: null\n\n' +
      'Texto:\n' + text.substring(0, 4000);
  }

  results.push({ json: { fileName, prompt }, binary: item.binary });
}
return results;

const items = $input.all();
const results = [];
const seen = new Map();
const sourceItems = $('Build LLM Prompt').all();

let folderId;
try {
  const existingFolders = $('Find existing folder').all();
  folderId = existingFolders.length > 0 ? existingFolders[0].json.id : $('Create folder').first().json.id;
} catch (e) {
  folderId = $('Create folder').first().json.id;
}

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const fileName = item.json.fileName || 'unknown.pdf';
  const binary = item.binary?.data || sourceItems[i]?.binary?.data;
  const llmResponse = item.json.llmResponse || item.json.choices?.[0]?.message?.content || '';
  let invoiceData = {};
  let renameStatus = 'error';
  let newName = fileName;
  let monthYear = '';

  try {
    let jsonStr = llmResponse;
    const codeBlockMatch = llmResponse.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (codeBlockMatch) jsonStr = codeBlockMatch[1];
    const jsonMatch = jsonStr.match(/\{[\s\S]*\}/);
    if (jsonMatch) invoiceData = JSON.parse(jsonMatch[0]);
  } catch (e) {
    invoiceData = { erro: 'JSON parse failed: ' + e.message };
  }

  if (invoiceData.erro) {
    renameStatus = 'not_fiscal';
  } else if (invoiceData.emitente && invoiceData.data_emissao) {
    const parts = invoiceData.data_emissao.split('-');
    const year = parts[0];
    const month = parts[1];
    monthYear = month + '-' + year;

    const tipo = (invoiceData.tipo || 'FT').toUpperCase();
    let emitente = invoiceData.emitente.replace(/[^a-zA-Z0-9]/g, '').substring(0, 30);

    const dedupKey = ((invoiceData.nif || emitente).toLowerCase()) + '-' + invoiceData.data_emissao;
    const count = (seen.get(dedupKey) || 0) + 1;
    seen.set(dedupKey, count);

    const suffix = count > 1 ? '_' + count : '';
    newName = month + '_' + year + '_' + tipo + '_' + emitente + suffix + '.pdf';
    renameStatus = 'renamed';
  } else {
    renameStatus = 'partial';
  }

  results.push({
    json: { originalName: fileName, fileName: newName, renameStatus, monthYear, invoiceData, folderId },
    binary: binary ? { data: binary } : undefined
  });
}
return results;

const items = $input.all();
const sourceItems = $('Join Upload Paths').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const binary = item.binary?.data || sourceItems[i]?.binary?.data;
  const fileName = item.json.fileName || sourceItems[i]?.json?.fileName || '';
  const folderId = item.json.folderId || sourceItems[i]?.json?.folderId || '';

  if (!binary) {
    results.push({ json: { fileName, folderId, gdriveStatus: 'skipped' } });
    continue;
  }
  results.push({ json: { fileName, folderId, gdriveStatus: 'uploaded' }, binary: { data: binary } });
}
return results;

const API_BASE = 'https://api.octacode.pt';
const COMPANY = 'RAMONCARLOS';
const DOC_TYPE = 'geraldocs';

const authData = $('Octa Auth').first().json;
const accessToken = authData.access_token || '';
const CLIENT_ID = String(authData.client_id || '336');

if (!accessToken) {
  return $input.all().map(i => ({ json: { fileName: i.json.fileName || '', folderId: i.json.folderId || '', octaStatus: 'auth_failed', octaError: 'No access_token from sub-workflow' } }));
}

const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const fileName = item.json.fileName || 'unknown.pdf';
  const folderId = item.json.folderId || '';

  if (!item.binary?.data) {
    results.push({ json: { fileName, folderId, octaStatus: 'skipped' } });
    continue;
  }
  try {
    const qs = 'client_id=' + encodeURIComponent(CLIENT_ID) +
      '&license_code=' +
      '&company_name=' + encodeURIComponent(COMPANY) +
      '&document_type=' + encodeURIComponent(DOC_TYPE) +
      '&document_name=' + encodeURIComponent(fileName);

    const presignResp = await this.helpers.httpRequest({
      method: 'GET',
      url: API_BASE + '/documentstorage/upload?' + qs,
      headers: { 'Authorization': 'Bearer ' + accessToken, 'Accept': 'application/json' },
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });
    const presignedUrl = presignResp.body?.attributes;
    if (!presignedUrl) throw new Error('No presigned URL: ' + JSON.stringify(presignResp.body));

    const pdfBuffer = await this.helpers.getBinaryDataBuffer(i, 'data');
    const uploadResp = await this.helpers.httpRequest({
      method: 'PUT',
      url: presignedUrl,
      body: pdfBuffer,
      headers: { 'Content-Type': 'application/pdf' },
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });
    results.push({ json: { fileName, folderId, octaStatus: uploadResp.statusCode < 300 ? 'uploaded' : 'failed', octaCode: uploadResp.statusCode } });
  } catch (err) {
    results.push({ json: { fileName, folderId, octaStatus: 'error', octaError: err.message } });
  }
}
return results;

const items = $input.all();
const stats = { uploaded: 0, failed: 0, skipped: 0, error: 0 };

let dedupSkipped = 0;
try {
  const dedupItems = $('Dedup Check').all();
  dedupSkipped = dedupItems[0]?.json?._dedupSkippedCount || 0;
} catch (e) {}

for (const item of items) {
  const s = item.json.octaStatus || 'unknown';
  if (stats[s] !== undefined) stats[s]++;
  else stats.error++;
}

const total = items.length + dedupSkipped;
const allOk = stats.failed === 0 && stats.error === 0;
const icon = allOk ? '✅' : '⚠️';

const details = items.map(i => {
  const s = i.json.octaStatus || '?';
  const dot = s === 'uploaded' ? '✅' : s === 'skipped' ? '⏭️' : '❌';
  return dot + ' ' + (i.json.fileName || 'unknown');
}).join('\n');

let summary = 'Notificar o chefe que as faturas foram renomeadas e enviadas.\n\n';
summary += icon + ' Invoice Upload — ' + (allOk ? 'All good' : 'Issues found') + '\n';
summary += '📄 ' + total + ' file' + (total !== 1 ? 's' : '') + ' processed\n';
summary += '☁️ Octa Manager: ' + stats.uploaded + ' uploaded';
if (stats.failed > 0) summary += ', ' + stats.failed + ' failed';
if (stats.skipped > 0) summary += ', ' + stats.skipped + ' skipped';
if (stats.error > 0) summary += ', ' + stats.error + ' error(s)';
if (dedupSkipped > 0) summary += '\n🔁 Dedup: ' + dedupSkipped + ' already existed (skipped)';
summary += '\n\n' + details;

return [{ json: {
  message: summary,
  stats,
  dedupSkipped,
  webhook_secret: 'n8n-webhook-secret-2024',
  webhook_url: 'http://192.168.50.11:8644/webhooks/n8n-complete'
} }];

const TOOLBOX_URL = 'http://toolbox.apps.svc.cluster.local:8000/api/v1/extract/base64';
const FIELD_NAME = 'data';

const allItems = $input.all();
const results = [];

for (let i = 0; i < allItems.length; i++) {
  try {
    const item = allItems[i];
    await this.helpers.assertBinaryData(i, FIELD_NAME);
    const buffer = await this.helpers.getBinaryDataBuffer(i, FIELD_NAME);

    const binary = item.binary?.[FIELD_NAME];
    const fileName = binary?.fileName || 'invoice.pdf';
    const mimeType = binary?.mimeType || 'application/pdf';

    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: TOOLBOX_URL,
      headers: { 'Content-Type': 'application/json' },
      body: {
        fileName,
        mimeType,
        data: buffer.toString('base64'),
      },
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
      timeout: 60000,
    });

    const status = response?.statusCode ?? 0;
    const payload = response?.body ?? null;
    if (status < 200 || status >= 300) {
      throw new Error(
        'Toolbox /extract/base64 returned ' + status + ': ' + (typeof payload === 'string' ? payload : JSON.stringify(payload))
      );
    }

    const jsonOut = typeof payload === 'object' && payload !== null
      ? { fileName, mimeType, ...payload }
      : { fileName, mimeType, _raw: payload };

    results.push({ json: jsonOut, binary: item.binary });
  } catch (err) {
    results.push({
      json: { fileName: (allItems[i].binary?.[FIELD_NAME]?.fileName || '?'), extractError: err.message },
      pairedItem: { item: i },
    });
  }
}

return results;

