const items = $input.all();

let folderId;
try {
  const existingFolders = $('Find existing folder').all();
  folderId = existingFolders.length > 0 ? existingFolders[0].json.id : $('Create folder').first().json.id;
} catch (e) {
  folderId = $('Create folder').first().json.id;
}

return items.map(item => {
  const fileName = item.json.fileName || '';

  let monthYear = '';
  const nlMatch = fileName.match(/^NL\s+(\d{4})(\d{2})\d+\.pdf$/i);
  if (nlMatch) {
    monthYear = nlMatch[2] + '-' + nlMatch[1];
  } else {
    const d = new Date();
    d.setMonth(d.getMonth() - 1);
    const mm = String(d.getMonth() + 1).padStart(2, '0');
    const yyyy = String(d.getFullYear());
    monthYear = mm + '-' + yyyy;
  }

  return {
    json: {
      folderId,
      originalName: fileName,
      fileName,
      renameStatus: 'original',
      monthYear,
      invoiceData: {},
    },
    binary: item.binary,
  };
});

const uploadItems = $input.all();

let existingItems = [];
try {
  existingItems = $('List files in folder').all();
} catch (e) {
  existingItems = [];
}

const existingNames = new Set(
  existingItems.map(item => (item.json.name || '').toLowerCase())
);

const newItems = [];
let skippedCount = 0;

for (const item of uploadItems) {
  const fileName = (item.json.fileName || '').toLowerCase();
  if (existingNames.has(fileName)) {
    skippedCount++;
  } else {
    newItems.push(item);
  }
}

if (newItems.length > 0) {
  newItems[0].json._dedupSkippedCount = skippedCount;
}

return newItems;
